output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?person ?label WHERE {
  ?person rdfs:label 'Rashi' @en
}
LIMIT 1

args.sparql:
SELECT ?person ?label WHERE {
  ?person wdt:P106 wd:Q143578;
          rdfs:label ?label.
  FILTER (LANG(?label) = 'en')
  SERVICE wikibase:entity { wd:Q143578 wikibase:label 'rabbi'@en }
} LIMIT 10

SELECT ?person ?label WHERE {
  ?person wdt:P106 wd:Q143578;
          rdfs:label ?label.
  FILTER (LANG(?label) = 'en')
} LIMIT 10

SELECT ?person ?label WHERE {
  ?person wdt:P106 wd:Q143578;
          rdfs:label ?label.
  FILTER (LANG(?label) = 'en')
  FILTER (CONTAINS(LCASE(STR(?label)), 'rav'))
} LIMIT 10

SELECT ?person ?label WHERE {
  ?person wdt:P106 wd:Q143578;
          rdfs:label ?label.
  FILTER (LANG(?label) = 'en' && ?label = 'Rashi')
}

SELECT ?person ?label WHERE {
  ?person wdt:P106 wd:Q143578;
          rdfs:label ?label.
  FILTER (LANG(?label) = 'en' && LCASE(STR(?label)) = 'rashi')
} LIMIT 1

SELECT ?person ?label WHERE {
  ?person wdt:P106 wd:Q143578;
          rdfs:label ?label.
  FILTER (LANG(?label) = 'en' && STR(?label) = 'Rashi')
} LIMIT 1
